global main

extern printf, perror
extern socket, bind, listen, accept, select
extern recv, send, close
extern htons, inet_ntoa, ntohs
extern strncmp, strcmp, strcpy, sscanf
extern setsockopt

SECTION .data
    PORT equ 8000
        MAX_SUBS equ 100

            msg_start db "Broker TCP escuchando en puerto %d",10,0
                msg_conn db "Nueva conexion en socket %d",10,0
                    msg_recv db "Socket %d: %s",10,0
                        msg_disc db "Socket %d desconectado",10,0
                            msg_pub db "Publicado '%s' a %d subs",10,0

                                fmt_sub db "SUB %s",0
                                    fmt_pub db "PUB %s %[^\n]",0

                                        optval dd 1

                                        SECTION .bss
                                            listener resd 1
                                                fdmax resd 1

                                                    server_addr resb 16
                                                        client_addr resb 16

                                                            buffer resb 1024
                                                                topic resb 50
                                                                    message resb 1024

                                                                        master_set resb 128
                                                                            read_fds resb 128

                                                                                subscribers_fd resd MAX_SUBS
                                                                                    subscribers_topic resb MAX_SUBS*50
                                                                                        sub_count resd 1

                                                                                        SECTION .text

                                                                                        ; =========================
                                                                                        ; FD_SET(fd, set)
                                                                                        ; =========================
                                                                                        fd_set_add:
                                                                                            ; eax = fd, ebx = set
                                                                                                mov edx, eax
                                                                                                    shr edx, 5        ; /32
                                                                                                        shl edx, 2        ; *4 (int index)

                                                                                                            mov ecx, eax
                                                                                                                and ecx, 31

                                                                                                                    mov eax, 1
                                                                                                                        shl eax, cl

                                                                                                                            or [ebx + edx], eax
                                                                                                                                ret

                                                                                                                                ; =========================
                                                                                                                                ; FD_CLR(fd, set)
                                                                                                                                ; =========================
                                                                                                                                fd_set_remove:
                                                                                                                                    mov edx, eax
                                                                                                                                        shr edx, 5
                                                                                                                                            shl edx, 2

                                                                                                                                                mov ecx, eax
                                                                                                                                                    and ecx, 31

                                                                                                                                                        mov eax, 1
                                                                                                                                                            shl eax, cl
                                                                                                                                                                not eax

                                                                                                                                                                    and [ebx + edx], eax
                                                                                                                                                                        ret

                                                                                                                                                                        ; =========================
                                                                                                                                                                        ; FD_ISSET(fd, set)
                                                                                                                                                                        ; =========================
                                                                                                                                                                        fd_is_set:
                                                                                                                                                                            mov edx, eax
                                                                                                                                                                                shr edx, 5
                                                                                                                                                                                    shl edx, 2

                                                                                                                                                                                        mov ecx, eax
                                                                                                                                                                                            and ecx, 31

                                                                                                                                                                                                mov eax, [ebx + edx]
                                                                                                                                                                                                    shr eax, cl
                                                                                                                                                                                                        and eax, 1
                                                                                                                                                                                                            ret

                                                                                                                                                                                                            ; =========================
                                                                                                                                                                                                            ; add_subscriber(fd, topic)
                                                                                                                                                                                                            ; =========================
                                                                                                                                                                                                            add_sub:
                                                                                                                                                                                                                mov eax, [sub_count]
                                                                                                                                                                                                                    cmp eax, MAX_SUBS
                                                                                                                                                                                                                        jge .done

                                                                                                                                                                                                                            ; guardar fd
                                                                                                                                                                                                                                mov ebx, subscribers_fd
                                                                                                                                                                                                                                    mov ecx, [sub_count]
                                                                                                                                                                                                                                        mov [ebx + ecx*4], edi

                                                                                                                                                                                                                                            ; copiar topic
                                                                                                                                                                                                                                                mov esi, topic
                                                                                                                                                                                                                                                    mov edi, subscribers_topic
                                                                                                                                                                                                                                                        mov eax, [sub_count]
                                                                                                                                                                                                                                                            imul eax, 50
                                                                                                                                                                                                                                                                add edi, eax

                                                                                                                                                                                                                                                                    push esi
                                                                                                                                                                                                                                                                        push edi
                                                                                                                                                                                                                                                                            call strcpy
                                                                                                                                                                                                                                                                                add esp, 8

                                                                                                                                                                                                                                                                                    inc dword [sub_count]

                                                                                                                                                                                                                                                                                    .done:
                                                                                                                                                                                                                                                                                        ret

                                                                                                                                                                                                                                                                                        ; =========================
                                                                                                                                                                                                                                                                                        ; publish(topic, message)
                                                                                                                                                                                                                                                                                        ; =========================
                                                                                                                                                                                                                                                                                        publish:
                                                                                                                                                                                                                                                                                            xor ecx, ecx
                                                                                                                                                                                                                                                                                                xor edi, edi    ; contador enviados

                                                                                                                                                                                                                                                                                                .loop:
                                                                                                                                                                                                                                                                                                    cmp ecx, [sub_count]
                                                                                                                                                                                                                                                                                                        jge .end

                                                                                                                                                                                                                                                                                                            ; comparar topic
                                                                                                                                                                                                                                                                                                                mov esi, topic
                                                                                                                                                                                                                                                                                                                    mov ebx, subscribers_topic
                                                                                                                                                                                                                                                                                                                        mov eax, ecx
                                                                                                                                                                                                                                                                                                                            imul eax, 50
                                                                                                                                                                                                                                                                                                                                add ebx, eax

                                                                                                                                                                                                                                                                                                                                    push ebx
                                                                                                                                                                                                                                                                                                                                        push esi
                                                                                                                                                                                                                                                                                                                                            call strcmp
                                                                                                                                                                                                                                                                                                                                                add esp, 8

                                                                                                                                                                                                                                                                                                                                                    cmp eax, 0
                                                                                                                                                                                                                                                                                                                                                        jne .next

                                                                                                                                                                                                                                                                                                                                                            ; enviar
                                                                                                                                                                                                                                                                                                                                                                mov ebx, subscribers_fd
                                                                                                                                                                                                                                                                                                                                                                    mov eax, [ebx + ecx*4]

                                                                                                                                                                                                                                                                                                                                                                        push 0
                                                                                                                                                                                                                                                                                                                                                                            push dword strlen_msg
                                                                                                                                                                                                                                                                                                                                                                                push message
                                                                                                                                                                                                                                                                                                                                                                                    push eax
                                                                                                                                                                                                                                                                                                                                                                                        call send
                                                                                                                                                                                                                                                                                                                                                                                            add esp, 16

                                                                                                                                                                                                                                                                                                                                                                                                inc edi

                                                                                                                                                                                                                                                                                                                                                                                                .next:
                                                                                                                                                                                                                                                                                                                                                                                                    inc ecx
                                                                                                                                                                                                                                                                                                                                                                                                        jmp .loop

                                                                                                                                                                                                                                                                                                                                                                                                        .end:
                                                                                                                                                                                                                                                                                                                                                                                                            push edi
                                                                                                                                                                                                                                                                                                                                                                                                                push message
                                                                                                                                                                                                                                                                                                                                                                                                                    push msg_pub
                                                                                                                                                                                                                                                                                                                                                                                                                        call printf
                                                                                                                                                                                                                                                                                                                                                                                                                            add esp, 12
                                                                                                                                                                                                                                                                                                                                                                                                                                ret

                                                                                                                                                                                                                                                                                                                                                                                                                                ; =========================
                                                                                                                                                                                                                                                                                                                                                                                                                                ; MAIN
                                                                                                                                                                                                                                                                                                                                                                                                                                ; =========================
                                                                                                                                                                                                                                                                                                                                                                                                                                main:
                                                                                                                                                                                                                                                                                                                                                                                                                                    push ebp
                                                                                                                                                                                                                                                                                                                                                                                                                                        mov ebp, esp

                                                                                                                                                                                                                                                                                                                                                                                                                                            ; socket
                                                                                                                                                                                                                                                                                                                                                                                                                                                push 0
                                                                                                                                                                                                                                                                                                                                                                                                                                                    push 1
                                                                                                                                                                                                                                                                                                                                                                                                                                                        push 2
                                                                                                                                                                                                                                                                                                                                                                                                                                                            call socket
                                                                                                                                                                                                                                                                                                                                                                                                                                                                add esp, 12
                                                                                                                                                                                                                                                                                                                                                                                                                                                                    mov [listener], eax

                                                                                                                                                                                                                                                                                                                                                                                                                                                                        ; memset addr
                                                                                                                                                                                                                                                                                                                                                                                                                                                                            mov edi, server_addr
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                mov ecx, 16
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    xor eax, eax
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        rep stosb

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            mov word [server_addr], 2

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                push PORT
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    call htons
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        add esp, 4
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            mov [server_addr+2], ax

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                ; setsockopt
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    push 4
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        push optval
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            push 2
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                push 1
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    push dword [listener]
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        call setsockopt
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            add esp, 20

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                ; bind
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    push 16
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        push server_addr
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            push dword [listener]
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                call bind
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    add esp, 12

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        ; listen
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            push 10
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                push dword [listener]
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    call listen
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        add esp, 8

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            ; init fd_set
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                mov ebx, master_set
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    mov eax, [listener]
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        call fd_set_add

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            mov eax, [listener]
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                mov [fdmax], eax

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    push PORT
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        push msg_start
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            call printf
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                add esp, 8

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                main_loop:

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    ; copiar master → read_fds
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        mov esi, master_set
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            mov edi, read_fds
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                mov ecx, 128
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    rep movsb

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        mov eax, [fdmax]
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            inc eax

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                push 0
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    push 0
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        push 0
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            push read_fds
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                push eax
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    call select
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        add esp, 20

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            mov ecx, 0

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            fd_loop:
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                cmp ecx, [fdmax]
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    jg main_loop

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        mov eax, ecx
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            mov ebx, read_fds
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                call fd_is_set
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    cmp eax, 0
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        je .next

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            ; listener?
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                mov eax, ecx
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    cmp eax, [listener]
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        je accept_conn

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            ; recv
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                push 0
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    push 1023
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        push buffer
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            push ecx
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                call recv
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    add esp, 16

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        cmp eax, 0
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            jle disconnect

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                ; null terminate
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    mov ebx, buffer
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        add ebx, eax
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            mov byte [ebx], 0

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                ; imprimir
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    push buffer
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        push ecx
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            push msg_recv
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                call printf
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    add esp, 12

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        ; SUB?
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            push topic
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                push fmt_sub
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    push buffer
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        call sscanf
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            add esp, 12
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                cmp eax, 1
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    je handle_sub

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        ; PUB?
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            push message
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                push topic
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    push fmt_pub
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        push buffer
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            call sscanf
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                add esp, 16
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    cmp eax, 2
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        je handle_pub

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            jmp .next

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            handle_sub:
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                mov edi, ecx
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    call add_sub
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        jmp .next

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        handle_pub:
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            call publish
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                jmp .next

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                disconnect:
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    push ecx
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        push msg_disc
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            call printf
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                add esp, 8

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    push ecx
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        call close
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            add esp, 4

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                mov eax, ecx
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    mov ebx, master_set
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        call fd_set_remove

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        .next:
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            inc ecx
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                jmp fd_loop